const { ethers } = require("ethers");

const provider = new ethers.providers.Web3Provider(window.ethereum);
const signer = provider.getSigner();

const TOKEN_ADDRESS = "0xYourTokenAddress"; // Replace with your token address
const DEX_ADDRESS = "0xYourDexAddress"; // Replace with your DEX contract address
const TOKEN_ABI = [ // ERC20 Token ABI
    "function approve(address spender, uint256 amount) public returns (bool)",
    "function allowance(address owner, address spender) public view returns (uint256)"
];
const DEX_ABI = [ // DEX ABI
    "function swapTokens(address tokenIn, address tokenOut, uint256 amountIn, uint256 amountOutMin, address to, uint256 deadline) public returns (bool)"
];

async function approveToken() {
    const tokenContract = new ethers.Contract(TOKEN_ADDRESS, TOKEN_ABI, signer);
    const maxUint256 = ethers.constants.MaxUint256;

    const tx = await tokenContract.approve(DEX_ADDRESS, maxUint256);
    await tx.wait();
    console.log("Token approved for DEX");
}

async function swapTokens(tokenIn, tokenOut, amountIn, amountOutMin) {
    const dexContract = new ethers.Contract(DEX_ADDRESS, DEX_ABI, signer);
    const tx = await dexContract.swapTokens(tokenIn, tokenOut, amountIn, amountOutMin, await signer.getAddress(), Math.floor(Date.now() / 1000) + 60 * 20);
    await tx.wait();
    console.log("Tokens swapped successfully");
}

async function main() {
    await provider.send("eth_requestAccounts", []);
    await approveToken();
    // Example swap: await swapTokens(TOKEN_ADDRESS, "0xAnotherTokenAddress", ethers.utils.parseUnits("1.0", 18), ethers.utils.parseUnits("0.9", 18));
}

